2007 /// For floating-point classes that resolve to a single bit pattern, return that
2008 /// value.
2009 static Constant *getFPClassConstant(Type *Ty, FPClassTest Mask,
2010                                     bool IsCanonicalizing = false) {
2011   if (Mask == fcNone)
2012     return PoisonValue::get(Ty);
2013 
2014   if (Mask == fcPosZero)
2015     return Constant::getNullValue(Ty);
2016 
2017   // TODO: Support aggregate types that are allowed by FPMathOperator.
2018   if (Ty->isAggregateType())
2019     return nullptr;
2020 
2021   // Turn any possible snans into quiet if we can.
2022   if (Mask == fcNan && IsCanonicalizing)
2023     return ConstantFP::getQNaN(Ty);
2024 
2025   switch (Mask) {
2026   case fcNegZero:
2027     return ConstantFP::getZero(Ty, true);
2028   case fcPosInf:
2029     return ConstantFP::getInfinity(Ty);
2030   case fcNegInf:
2031     return ConstantFP::getInfinity(Ty, true);
2032   case fcQNan:
2033     // Payload bits cannot be dropped for pure signbit operations.
2034     return IsCanonicalizing ? ConstantFP::getQNaN(Ty) : nullptr;
2035   default:
2036     return nullptr;
2037   }
2038 }
