2040 /// Perform multiple-use aware simplfications for fabs(\p Src). Returns a
2041 /// replacement value if it's simplified, otherwise nullptr. Updates \p Known
2042 /// with the known fpclass if not simplified.
2043 static Value *simplifyDemandedFPClassFabs(KnownFPClass &Known, Value *Src,
2044                                           FPClassTest DemandedMask,
2045                                           KnownFPClass KnownSrc, bool NSZ) {
2046   if ((DemandedMask & fcNan) == fcNone)
2047     KnownSrc.knownNot(fcNan);
2048   if ((DemandedMask & fcInf) == fcNone)
2049     KnownSrc.knownNot(fcInf);
2050 
2051   if (KnownSrc.SignBit == false ||
2052       ((DemandedMask & fcNan) == fcNone && KnownSrc.isKnownNever(fcNegative)))
2053     return Src;
2054 
2055   // If the only sign bit difference is due to -0, ignore it with nsz
2056   if (NSZ &&
2057       KnownSrc.isKnownNever(KnownFPClass::OrderedLessThanZeroMask | fcNan))
2058     return Src;
2059 
2060   Known = KnownFPClass::fabs(KnownSrc);
2061   return nullptr;
2062 }
