2194 /// Try to set an inferred no-nans or no-infs in \p FMF. \p
2195 /// ValidResults is a mask of known valid results for the operator
2196 /// (already computed from the result, and the known operand inputs,
2197 /// \p KnownLHS and \p KnownRHS)
2198 static FastMathFlags
2199 inferFastMathValueFlagsBinOp(FastMathFlags FMF, FPClassTest ValidResults,
2200                              const KnownFPClass &KnownLHS,
2201                              const KnownFPClass &KnownRHS) {
2202   if (!FMF.noNaNs() && (ValidResults & fcNan) == fcNone &&
2203       KnownLHS.isKnownNeverNaN() && KnownRHS.isKnownNeverNaN())
2204     FMF.setNoNaNs();
2205 
2206   if (!FMF.noInfs() && (ValidResults & fcInf) == fcNone &&
2207       KnownLHS.isKnownNeverInfinity() && KnownRHS.isKnownNeverInfinity())
2208     FMF.setNoInfs();
2209 
2210   return FMF;
2211 }
