3197 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3198                                                FPClassTest DemandedMask,
3199                                                KnownFPClass &Known,
3200                                                unsigned Depth) {
3201   Use &U = I->getOperandUse(OpNo);
3202   Value *V = U.get();
3203   Type *VTy = V->getType();
3204 
3205   if (DemandedMask == fcNone) {
3206     if (isa<UndefValue>(V))
3207       return false;
3208     replaceUse(U, PoisonValue::get(VTy));
3209     return true;
3210   }
3211 
3212   // Handle constant
3213   Instruction *VInst = dyn_cast<Instruction>(V);
3214   if (!VInst) {
3215     // Handle constants and arguments
3216     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3217     Known.knownNot(~DemandedMask);
3218 
3219     if (Known.KnownFPClasses == fcNone) {
3220       if (isa<UndefValue>(V))
3221         return false;
3222       replaceUse(U, PoisonValue::get(VTy));
3223       return true;
3224     }
3225 
3226     // Do not try to replace values which are already constants (unless we are
3227     // folding to poison). Doing so could promote poison elements to non-poison
3228     // constants.
3229     if (isa<Constant>(V))
3230       return false;
3231 
3232     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3233     if (!FoldedToConst || FoldedToConst == V)
3234       return false;
3235 
3236     replaceUse(U, FoldedToConst);
3237     return true;
3238   }
3239 
3240   if (Depth == MaxAnalysisRecursionDepth)
3241     return false;
3242 
3243   Value *NewVal;
3244 
3245   if (VInst->hasOneUse()) {
3246     // If the instruction has one use, we can directly simplify it.
3247     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3248   } else {
3249     // If there are multiple uses of this instruction, then we can simplify
3250     // VInst to some other value, but not modify the instruction.
3251     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3252                                                 Depth);
3253   }
3254 
3255   if (!NewVal)
3256     return false;
3257   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3258     salvageDebugInfo(*OpInst);
3259 
3260   replaceUse(U, NewVal);
3261   return true;
3262 }
